import React, { useEffect, useRef } from 'react';
import Phaser from 'phaser';

const BallyGamboyGame = () => {
    const gameRef = useRef(null);
    let player;

    useEffect(() => {
        const initializeGame = () => {
            const config = {
                type: Phaser.AUTO,
                width: 800,
                height: 600,
                scene: {
                    preload: preload,
                    create: create
                },
                physics: {
                    default: 'arcade',
                    arcade: {
                        gravity: { y: 0 },
                        debug: false
                    }
                }
            };

            gameRef.current = new Phaser.Game(config);
        };
let champID = localStorage.getItem('champID')
        function preload() {
          this.load.image('player', './phaser-resources/images/champions/'+champID+'.png');
          this.load.image('background', './phaser-resources/images/placeholders/gamboy.png');
          this.load.image('upButton', './phaser-resources/images/ui/pad-u.png');
          this.load.image('middleButton', './phaser-resources/images/ui/middle-b.png');
          this.load.image('downButton', './phaser-resources/images/ui/pad-d.png');
          this.load.image('leftButton', './phaser-resources/images/ui/pad-l.png');
          this.load.image('rightButton', './phaser-resources/images/ui/pad-r.png');
      }

      function create() {
        // Create the background sprite and set its size to match the game's canvas
        const background = this.add.sprite(0, 0, 'background').setOrigin(0);
        background.displayWidth = this.sys.game.config.width;
        background.displayHeight = this.sys.game.config.height;

        // Load player sprite
        player = this.physics.add.sprite(50, 225, 'player'); // Add physics to the player sprite

        // Create directional pad buttons
        this.upButton = this.add.sprite(750, 250, 'upButton');
        this.downButton = this.add.sprite(750, 350, 'downButton');
        this.leftButton = this.add.sprite(700, 300, 'leftButton');
        this.rightButton = this.add.sprite(800, 300, 'rightButton');

        // Make buttons interactive
        this.upButton.setInteractive();
        this.downButton.setInteractive();
        this.leftButton.setInteractive();
        this.rightButton.setInteractive();
    }

    function setupEventListeners(scene) {
      // Listen for pointer down events on each button
      scene.upButton.on('pointerdown', () => movePlayer('up'));
      scene.downButton.on('pointerdown', () => movePlayer('down'));
      scene.leftButton.on('pointerdown', () => movePlayer('left'));
      scene.rightButton.on('pointerdown', () => movePlayer('right'));
  }




    function movePlayer(direction) {
      const speed = 500; // Adjust the speed as needed
      let destinationX = player.x;
      let destinationY = player.y;

      switch (direction) {
        case 'up':
          destinationY -= 200;
          break;
          case 'down':
            destinationY += 200;
            break;
            case 'left':
              destinationX -= 200;
              break;
              case 'right':
                destinationX += 200;
                break;
              }

              // Tween the player sprite to the destination coordinates
              gameRef.current.tweens.add({
                targets: player,
                x: destinationX,
                y: destinationY,
                duration: speed,
                ease: 'Linear',
              });
            }
            initializeGame();
            setupEventListeners(gameRef.current.scene.scenes[0]);

        return () => {
            if (gameRef.current) {
                gameRef.current.destroy(true);
            }
        };
    }, []);

    return <div id="ballygamboy-game-container"></div>;
};

export default BallyGamboyGame;
